import { useEffect, useState } from "react";

export default function Dashboard() {
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [search, setSearch] = useState("");
  const [priority, setPriority] = useState("ALL");
  const [status, setStatus] = useState("ALL");
  const [sort, setSort] = useState("latest");

  // 🔄 Fetch data
  const fetchData = async () => {
    try {
      setLoading(true);
      const res = await fetch("http://localhost:8000/incidents");
      const json = await res.json();
      setData(json);
      setError("");
    } catch {
      setError("Failed to load data");
    }
    setLoading(false);
  };

  // auto refresh
  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 3000);
    return () => clearInterval(interval);
  }, []);

  // 🎯 Filters
  let filtered = data.filter((i) => {
    return (
      (search === "" ||
        i.component_id.toLowerCase().includes(search.toLowerCase())) &&
      (priority === "ALL" || i.severity === priority) &&
      (status === "ALL" || i.status === status)
    );
  });

  // 🔽 Sorting
  filtered.sort((a, b) => {
    if (sort === "latest") return new Date(b.start_time) - new Date(a.start_time);
    if (sort === "signals") return b.signal_count - a.signal_count;
    return 0;
  });

  // 📊 Stats
  const total = data.length;
  const open = data.filter((i) => i.status === "OPEN").length;
  const closed = data.filter((i) => i.status === "CLOSED").length;

  // 🎨 Severity color
  const sevColor = (s) => {
    if (s === "P0") return "#ff4d4f";
    if (s === "P1") return "#ff9800";
    if (s === "P2") return "#fbc02d";
    if (s === "P3") return "#4caf50";
    return "#999";
  };

  return (
    <div style={page}>
      <h2>🚨 IT Incident Dashboard</h2>

      {/* STATS */}
      <div style={stats}>
        <Card title="Total" value={total} />
        <Card title="Open" value={open} color="#ff4d4f" />
        <Card title="Closed" value={closed} color="#4caf50" />
      </div>

      {/* FILTER BAR */}
      <div style={filters}>
        <input
          placeholder="Search component..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          style={input}
        />

        <select onChange={(e) => setPriority(e.target.value)}>
          <option value="ALL">All Priorities</option>
          <option>P0</option>
          <option>P1</option>
          <option>P2</option>
          <option>P3</option>
        </select>

        <select onChange={(e) => setStatus(e.target.value)}>
          <option value="ALL">All Status</option>
          <option>OPEN</option>
          <option>CLOSED</option>
        </select>

        <select onChange={(e) => setSort(e.target.value)}>
          <option value="latest">Sort: Latest</option>
          <option value="signals">Sort: Signals</option>
        </select>
      </div>

      {/* STATES */}
      {loading && <p>⏳ Loading...</p>}
      {error && <p style={{ color: "red" }}>{error}</p>}

      {/* INCIDENT CARDS */}
      <div style={grid}>
        {filtered.map((i) => (
          <div key={i.id} style={card}>
            <h3>{i.component_id}</h3>
            <p>Incident #{i.id}</p>

            <span style={{ ...badge, background: sevColor(i.severity) }}>
              {i.severity}
            </span>

            <p>Status: {i.status}</p>
            <p>Signals: {i.signal_count}</p>
            <p>{new Date(i.start_time).toLocaleString()}</p>

            <a href={`/incident/${i.id}`} style={btn}>
              View Details →
            </a>
          </div>
        ))}
      </div>
    </div>
  );
}

// 🧩 SMALL COMPONENT
const Card = ({ title, value, color = "#333" }) => (
  <div style={{ ...card, width: "150px" }}>
    <h4>{title}</h4>
    <h2 style={{ color }}>{value}</h2>
  </div>
);

// 🎨 STYLES
const page = {
  padding: "20px",
  fontFamily: "Segoe UI",
  background: "#f4f6f8",
  minHeight: "100vh"
};

const stats = {
  display: "flex",
  gap: "15px",
  marginBottom: "20px"
};

const filters = {
  display: "flex",
  gap: "10px",
  marginBottom: "20px"
};

const grid = {
  display: "grid",
  gridTemplateColumns: "repeat(auto-fit, minmax(250px, 1fr))",
  gap: "20px"
};

const card = {
  background: "#fff",
  padding: "15px",
  borderRadius: "10px",
  boxShadow: "0 2px 8px rgba(0,0,0,0.08)"
};

const input = {
  padding: "8px",
  borderRadius: "6px",
  border: "1px solid #ccc"
};

const badge = {
  padding: "4px 8px",
  borderRadius: "6px",
  color: "#fff",
  display: "inline-block",
  marginBottom: "5px"
};

const btn = {
  display: "inline-block",
  marginTop: "10px",
  padding: "6px 10px",
  background: "#2f6fed",
  color: "#fff",
  borderRadius: "6px",
  textDecoration: "none"
};
